int getSubMenuCount() {
  switch (currentCategory) {
    case CAT_WIFI:   return WIFI_MENU_COUNT;
    case CAT_BT:     return BT_MENU_COUNT;
    case CAT_OTHERS: return OTHERS_MENU_COUNT;
    default:         return 0;
  }
}
const char** getSubMenuItems() {
  switch (currentCategory) {
    case CAT_WIFI:   return wifiMenuItems;
    case CAT_BT:     return btMenuItems;
    case CAT_OTHERS: return othersMenuItems;
    default:         return nullptr;
  }
}

// ============================================================
// Smooth animation — easing with acceleration
// ============================================================
inline void animateSelection() {
  int diff = selTargetY - selY;
  if (diff == 0) return;
  // Smooth easing: move 45% of distance, minimum 1px
  int step = diff * 45 / 100;
  if (step == 0) step = (diff > 0) ? 1 : -1;
  selY += step;
  displayNeedsUpdate = true;
}

// ============================================================
// Helper: Draw rounded rectangle (pixel-perfect)
// ============================================================
void drawRoundRect(int x, int y, int w, int h, bool fill = false) {
  if (fill) {
    display.fillRect(x + 2, y, w - 4, h, SSD1306_WHITE);
    display.fillRect(x + 1, y + 1, w - 2, h - 2, SSD1306_WHITE);
    display.fillRect(x, y + 2, w, h - 4, SSD1306_WHITE);
  } else {
    display.drawFastHLine(x + 2, y, w - 4, SSD1306_WHITE);
    display.drawFastHLine(x + 2, y + h - 1, w - 4, SSD1306_WHITE);
    display.drawFastVLine(x, y + 2, h - 4, SSD1306_WHITE);
    display.drawFastVLine(x + w - 1, y + 2, h - 4, SSD1306_WHITE);
    display.drawPixel(x + 1, y + 1, SSD1306_WHITE);
    display.drawPixel(x + w - 2, y + 1, SSD1306_WHITE);
    display.drawPixel(x + 1, y + h - 2, SSD1306_WHITE);
    display.drawPixel(x + w - 2, y + h - 2, SSD1306_WHITE);
  }
}

// ============================================================
// Helper: Animated dots
// ============================================================
const char* getAnimDots() {
  int phase = (millis() / 400) % 4;
  switch(phase) {
    case 0: return "";
    case 1: return ".";
    case 2: return "..";
    default: return "...";
  }
}

// ============================================================
// Helper: Draw progress bar with animation
// ============================================================
void drawProgressBar(int x, int y, int w, int h, int val, int maxVal) {
  drawRoundRect(x, y, w, h, false);
  int fillW = map(constrain(val, 0, maxVal), 0, maxVal, 0, w - 4);
  if (fillW > 0) {
    display.fillRect(x + 2, y + 2, fillW, h - 4, SSD1306_WHITE);
  }
}

// ============================================================
// Status Bar (top) — compact info bar with device info
// ============================================================
void drawStatusBar() {
  // Top line: ghostwave icon + name + mode indicator
  display.drawBitmap(0, 0, icon_ghost_sm, 8, 8, SSD1306_WHITE);
  display.setTextSize(1);
  display.setTextColor(SSD1306_WHITE);
  display.setCursor(10, 0);
  display.print("GhostWave");

  // Mode indicator on right
  if (currentMode != MODE_IDLE) {
    // Pulsing dot for active
    if ((millis() / 300) % 2) {
      display.fillCircle(122, 3, 2, SSD1306_WHITE);
    } else {
      display.drawCircle(122, 3, 2, SSD1306_WHITE);
    }
    display.setCursor(108, 0);
    display.print("ON");
  }

  // Separator line
  display.drawFastHLine(0, 9, 128, SSD1306_WHITE);
}

// ============================================================
// Modern Header Bar (for sub-screens)
// ============================================================
void drawHeader(const char* title) {
  drawRoundRect(0, 0, 128, 11, true);
  display.setTextColor(SSD1306_BLACK);
  display.setTextSize(1);
  int titleLen = strlen(title);
  int startX = (128 - titleLen * 6) / 2;
  display.setCursor(startX, 2);
  display.print(title);
  display.setTextColor(SSD1306_WHITE);
}

// ============================================================
// Footer Bar — context-sensitive
// ============================================================
void drawFooter(const char* text) {
  display.drawFastHLine(0, 54, 128, SSD1306_WHITE);
  display.setTextSize(1);
  display.setTextColor(SSD1306_WHITE);
  int textLen = strlen(text);
  int startX = (128 - textLen * 6) / 2;
  display.setCursor(startX, 56);
  display.print(text);
}

// ============================================================
// Active indicator (pulsing dot)
// ============================================================
void drawActiveIndicator() {
  if (currentMode != MODE_IDLE) {
    int pulse = (millis() / 300) % 2;
    if (pulse) {
      display.fillCircle(122, 57, 2, SSD1306_WHITE);
    } else {
      display.drawCircle(122, 57, 2, SSD1306_WHITE);
    }
  }
}

// ============================================================
// Main Menu — compact card layout, no overlap
// ============================================================
void drawMainMenu() {
  display.clearDisplay();
  display.setTextSize(1);
  display.setTextColor(SSD1306_WHITE);

  // Status bar at top (y=0..9)
  drawStatusBar();

  // 3 cards, 13px height, 14px spacing
  // Card 0: y=11..23, Card 1: y=25..37, Card 2: y=39..51
  // Footer: y=53+ — no overlap!
  selTargetY = 11 + mainMenuIndex * 14;
  animateSelection();

  // Draw selection highlight
  drawRoundRect(0, selY, 128, 13, true);

  for (int i = 0; i < CAT_COUNT; i++) {
    int y = 11 + i * 14;
    bool selected = (y + 12 > selY && y < selY + 13);

    if (!selected) {
      drawRoundRect(0, y, 128, 13, false);
    }

    // Icon
    const unsigned char* icon = (i == 0) ? icon_wifi : (i == 1) ? icon_bt : icon_other;
    display.drawBitmap(4, y + 3, icon, 8, 8, selected ? SSD1306_BLACK : SSD1306_WHITE);

    // Label
    display.setTextColor(selected ? SSD1306_BLACK : SSD1306_WHITE);
    display.setCursor(16, y + 3);
    display.print(mainMenuLabels[i]);

    // Arrow
    display.setCursor(120, y + 3);
    display.print(">");
  }

  // Footer: show description of selected category
  display.setTextColor(SSD1306_WHITE);
  display.drawFastHLine(0, 53, 128, SSD1306_WHITE);
  display.setCursor(2, 55);
  display.print(mainMenuDesc[mainMenuIndex]);

  // Uptime on right side of footer
  unsigned long sec = millis() / 1000;
  char ut[10];
  snprintf(ut, sizeof(ut), "%lu:%02lu", sec / 60, sec % 60);
  int utLen = strlen(ut);
  display.setCursor(128 - utLen * 6 - 1, 55);
  display.print(ut);

  display.display();
}

// ============================================================
// Submenu — smooth scrollable list with item count
// ============================================================
void drawSubMenu() {
  display.clearDisplay();

  // Header with category name + item counter
  char hdr[24];
  int itemCount = getSubMenuCount();
  snprintf(hdr, sizeof(hdr), "%s [%d/%d]", mainMenuLabels[(int)currentCategory], subMenuIndex + 1, itemCount);
  drawHeader(hdr);
  display.setTextColor(SSD1306_WHITE);

  const char** items = getSubMenuItems();
  if (!items) { display.display(); return; }

  if (subMenuIndex < subMenuScroll) subMenuScroll = subMenuIndex;
  if (subMenuIndex >= subMenuScroll + VISIBLE_ITEMS) subMenuScroll = subMenuIndex - VISIBLE_ITEMS + 1;

  selTargetY = (subMenuIndex - subMenuScroll) * 10 + 13;
  animateSelection();

  // Selection highlight
  drawRoundRect(0, selY - 1, 126, 10, true);

  // Draw items
  int y = 13;
  for (int i = subMenuScroll; i < subMenuScroll + VISIBLE_ITEMS && i < itemCount; i++) {
    bool inBar = (y >= selY - 1 && y <= selY + 8);
    display.setTextColor(inBar ? SSD1306_BLACK : SSD1306_WHITE);

    display.setCursor(3, y);
    if (strcmp(items[i], "< Back") != 0) {
      display.print("\x07 ");
    } else {
      display.print("< ");
    }
    display.print(items[i]);
    y += 10;
  }

  // Scroll indicators (thin arrows)
  display.setTextColor(SSD1306_WHITE);
  if (subMenuScroll > 0) {
    display.fillTriangle(122, 14, 126, 14, 124, 12, SSD1306_WHITE);
  }
  if (subMenuScroll + VISIBLE_ITEMS < itemCount) {
    display.fillTriangle(122, 44, 126, 44, 124, 46, SSD1306_WHITE);
  }

  // Footer with mode info
  if (currentMode != MODE_IDLE) {
    char buf[22];
    snprintf(buf, sizeof(buf), "ACTIVE | Pkts:%lu", (unsigned long)packetCount);
    drawFooter(buf);
  } else {
    drawFooter("OK=Select  BK=Back");
  }
  drawActiveIndicator();
  display.display();
}

// ============================================================
// Scan Results — modern list with signal bars + channel
// ============================================================
void drawScanResults() {
  display.clearDisplay();

  char hdr[20];
  snprintf(hdr, sizeof(hdr), "APs Found: %d", scanCount);
  drawHeader(hdr);
  display.setTextColor(SSD1306_WHITE);

  if (scanCount == 0) {
    display.setCursor(20, 28);
    display.print("No APs found");
    drawFooter("BK=Back");
    display.display();
    return;
  }

  if (scanMenuIndex < scanMenuScroll) scanMenuScroll = scanMenuIndex;
  if (scanMenuIndex >= scanMenuScroll + VISIBLE_ITEMS) scanMenuScroll = scanMenuIndex - VISIBLE_ITEMS + 1;

  int y = 13;
  for (int i = scanMenuScroll; i < scanMenuScroll + VISIBLE_ITEMS && i < scanCount; i++) {
    if (i == scanMenuIndex) {
      drawRoundRect(0, y - 1, 128, 10, true);
      display.setTextColor(SSD1306_BLACK);
    } else {
      display.setTextColor(SSD1306_WHITE);
    }
    display.setCursor(2, y);
    String ssid = scanResults[i].ssid;
    if (ssid.length() > 12) ssid = ssid.substring(0, 12);
    display.print(ssid);

    // Signal strength bars (3 bars)
    int sig = map(constrain(scanResults[i].rssi, -90, -30), -90, -30, 0, 12);
    bool isBlack = (i == scanMenuIndex);
    for (int b = 0; b < 3; b++) {
      int barH = 2 + b * 2;
      int barX = 90 + b * 5;
      int barY = y + 7 - barH;
      if (b * 4 < sig) {
        display.fillRect(barX, barY, 3, barH, isBlack ? SSD1306_BLACK : SSD1306_WHITE);
      } else {
        display.drawRect(barX, barY, 3, barH, isBlack ? SSD1306_BLACK : SSD1306_WHITE);
      }
    }

    // Channel number
    display.setCursor(108, y);
    display.print(scanResults[i].channel);
    display.setTextColor(SSD1306_WHITE);
    y += 10;
  }

  drawFooter("OK=Deauth BK=Back");
  display.display();
}

// ============================================================
// Running Screen — attack dashboard with live stats
// ============================================================
void drawRunningScreen() {
  display.clearDisplay();

  // Inverted header with attack name
  drawHeader("ATTACK ACTIVE");
  display.setTextColor(SSD1306_WHITE);

  // Attack type line
  display.setCursor(4, 14);
  switch(currentMode) {
    case MODE_BLE_ALL:     display.print("\x07 BLE Spam ALL"); break;
    case MODE_BLE_SAMSUNG: display.print("\x07 BLE Samsung"); break;
    case MODE_BLE_WINDOWS: display.print("\x07 BLE Windows"); break;
    case MODE_BLE_APPLE:   display.print("\x07 BLE Apple"); break;
    case MODE_BLE_ANDROID: display.print("\x07 BLE Android"); break;
    case MODE_BLE_SCAN:    display.print("\x07 BLE Scanner"); break;
    case MODE_WIFI_DEAUTH:
      display.print("\x07 Deauth: ");
      if (deauthTarget >= 0 && deauthTarget < scanCount) {
        String s = scanResults[deauthTarget].ssid;
        if (s.length() > 9) s = s.substring(0, 9);
        display.print(s);
      }
      break;
    case MODE_WIFI_BEACON:        display.print("\x07 Beacon GW"); break;
    case MODE_WIFI_BEACON_RANDOM: display.print("\x07 Beacon Rand"); break;
    default: break;
  }

  // Separator
  display.drawFastHLine(2, 24, 124, SSD1306_WHITE);

  // Stats section
  display.setCursor(4, 28);
  if (currentMode == MODE_WIFI_DEAUTH) {
    display.print("Pkts: ");
    display.print(deauthPackets);
    drawProgressBar(70, 27, 54, 8, deauthPackets % 100, 100);
  } else if (currentMode >= MODE_BLE_ALL && currentMode <= MODE_BLE_ANDROID) {
    display.print("Sending");
    display.print(getAnimDots());

    // Packet count
    display.setCursor(4, 38);
    display.print("Pkts: ");
    display.print(packetCount);
  } else if (currentMode == MODE_BLE_SCAN) {
    display.print("Found: ");
    display.print(bleDeviceCount);
    display.setCursor(4, 40);
    char truncName[18];
    strncpy(truncName, lastBleName, 17);
    truncName[17] = '\0';
    display.print(truncName);
  } else {
    unsigned long elapsed = (millis() - attackStartTime) / 1000;
    display.print("Time: ");
    display.print(elapsed);
    display.print("s");
    drawProgressBar(70, 27, 54, 8, elapsed % 60, 60);
  }

  // Elapsed time at bottom
  unsigned long elapsed = (millis() - attackStartTime) / 1000;
  display.setCursor(4, 44);
  display.print("T:");
  display.print(elapsed / 60);
  display.print("m");
  display.print(elapsed % 60);
  display.print("s");

  // Pulsing border for active state
  if ((millis() / 500) % 2) {
    display.drawRect(0, 12, 128, 40, SSD1306_WHITE);
  }

  drawFooter("BACK = STOP");
  display.display();
}

