// ============================================================
// Boot Screen — GhostWave animated intro
// ============================================================
void showBootScreen() {
  // Phase 1: Ghost logo materializes line by line
  for (int row = 0; row <= 40; row += 2) {
    display.clearDisplay();
    // Draw partial ghost bitmap (row by row reveal)
    display.drawBitmap(32, 2, ghost_logo, 64, row, SSD1306_WHITE);
    display.display();
    delay(25);
  }

  // Phase 2: Full ghost + aura pulse
  for (int pulse = 0; pulse < 4; pulse++) {
    display.clearDisplay();
    display.drawBitmap(32, 2, ghost_logo, 64, 40, SSD1306_WHITE);

    // Pulsing aura ring around ghost
    int r = 24 + pulse * 3;
    display.drawCircle(64, 22, r, SSD1306_WHITE);
    if (pulse > 0) display.drawCircle(64, 22, r - 3, SSD1306_WHITE);

    display.display();
    delay(120);
  }

  // Phase 3: Ghost + text slide in
  for (int frame = 0; frame < 12; frame++) {
    display.clearDisplay();
    display.drawBitmap(32, 2, ghost_logo, 64, 40, SSD1306_WHITE);

    // "GhostWave" text slides from right
    int textX = 128 - frame * 12;
    if (textX < 16) textX = 16;
    display.setTextSize(1);
    display.setTextColor(SSD1306_WHITE);
    display.setCursor(textX, 46);
    display.print("G h o s t W a v e");

    // Version slides from left
    int verX = -60 + frame * 8;
    if (verX > 28) verX = 28;
    display.setCursor(verX, 56);
    display.print("Multi-Tool v3.0");

    display.display();
    delay(60);
  }

  // Phase 4: Hold with pulsing aura
  for (int i = 0; i < 8; i++) {
    display.clearDisplay();
    display.drawBitmap(32, 2, ghost_logo, 64, 40, SSD1306_WHITE);

    // Pulsing aura particles
    int spark = (i % 3);
    if (spark == 0) {
      display.drawPixel(20, 10, SSD1306_WHITE);
      display.drawPixel(108, 15, SSD1306_WHITE);
      display.drawPixel(25, 35, SSD1306_WHITE);
      display.drawPixel(100, 30, SSD1306_WHITE);
    } else if (spark == 1) {
      display.drawPixel(15, 20, SSD1306_WHITE);
      display.drawPixel(112, 8, SSD1306_WHITE);
      display.drawPixel(22, 28, SSD1306_WHITE);
      display.drawPixel(105, 38, SSD1306_WHITE);
    }

    display.setTextSize(1);
    display.setTextColor(SSD1306_WHITE);
    display.setCursor(16, 46);
    display.print("G h o s t W a v e");
    display.setCursor(28, 56);
    display.print("Multi-Tool v3.0");

    display.display();
    delay(100);
  }

  // Phase 5: Scanline wipe transition
  for (int y = 0; y < 64; y += 2) {
    display.drawFastHLine(0, y, 128, SSD1306_BLACK);
    display.drawFastHLine(0, y + 1, 128, SSD1306_BLACK);
    display.display();
    delay(12);
  }
}

