// ============================================================
// Tamagotchi Screen — Cute interactive ghost pet
// ============================================================
void drawTamagotchiScreen() {
  display.clearDisplay();
  unsigned long t = millis();
  display.setTextSize(1);
  display.setTextColor(SSD1306_WHITE);

  // --- Determine ghost mood based on actual stats ---
  const unsigned char* ghostFace;
  const char* moodText;
  int avgStat = (tgHunger + tgHappy + tgEnergy) / 3;

  if (tgAction == 1) {
    ghostFace = ghost_hungry;   // eating animation
    moodText = "Nom!";
  } else if (tgAction == 2) {
    ghostFace = ghost_play;     // playing animation
    moodText = "Whee!";
  } else if (tgAction == 3) {
    ghostFace = ghost_sleepy;   // sleeping animation
    moodText = "Zzz..";
  } else if (tgEnergy < 20) {
    ghostFace = ghost_sleepy;
    moodText = "Tired";
  } else if (tgHunger < 20) {
    ghostFace = ghost_hungry;
    moodText = "Hungry";
  } else if (avgStat > 70) {
    ghostFace = ghost_happy;
    moodText = "Happy!";
  } else if (avgStat > 40) {
    ghostFace = ghost_happy;
    moodText = "OK";
  } else {
    ghostFace = ghost_hungry;
    moodText = "Sad..";
  }

  // --- Ghost position with bobbing ---
  int bobX = 4 + (int)(2.0 * sin(t / 500.0));
  int bobY = 6 + (int)(2.0 * sin(t / 700.0));

  // Extra bounce during actions
  if (tgAction == 2) {
    bobY -= abs((int)(4.0 * sin(t / 150.0)));  // jumpy when playing
  } else if (tgAction == 3) {
    bobY += 2;  // sink down when sleeping
  }

  // --- Draw ghost ---
  display.drawBitmap(bobX, bobY, ghostFace, 24, 24, SSD1306_WHITE);

  // --- Action feedback particles ---
  if (tgAction == 1) {
    // Floating food sparkles
    for (int s = 0; s < 3; s++) {
      int sx = bobX + 26 + s * 6;
      int sy = bobY + 8 - (int)((t - tgActionTime) / 100) + s * 3;
      if (sy > bobY - 4 && sy < bobY + 20) {
        display.drawPixel(sx, sy, SSD1306_WHITE);
        display.drawPixel(sx + 1, sy - 1, SSD1306_WHITE);
      }
    }
  } else if (tgAction == 2) {
    // Stars around ghost
    int starPhase = ((t - tgActionTime) / 200) % 4;
    for (int s = 0; s <= starPhase && s < 3; s++) {
      int sx = bobX - 2 + s * 14;
      int sy = bobY - 3 + (s % 2) * 8;
      // tiny star: +
      display.drawPixel(sx, sy, SSD1306_WHITE);
      display.drawPixel(sx - 1, sy, SSD1306_WHITE);
      display.drawPixel(sx + 1, sy, SSD1306_WHITE);
      display.drawPixel(sx, sy - 1, SSD1306_WHITE);
      display.drawPixel(sx, sy + 1, SSD1306_WHITE);
    }
  } else if (tgAction == 3) {
    // Floating Z's
    int zPhase = ((t - tgActionTime) / 400) % 4;
    for (int z = 0; z < zPhase && z < 3; z++) {
      display.setCursor(bobX + 22 + z * 7, bobY - 2 - z * 5);
      display.print("z");
    }
  }

  // --- Idle decorations ---
  if (tgAction == 0 && avgStat > 60) {
    // Floating hearts when happy
    if ((t / 2000) % 3 == 0) {
      int hx = bobX + 26, hy = bobY + 2 - (int)((t % 2000) / 200);
      display.drawPixel(hx, hy + 1, SSD1306_WHITE);
      display.drawPixel(hx + 2, hy + 1, SSD1306_WHITE);
      display.drawPixel(hx - 1, hy, SSD1306_WHITE);
      display.drawPixel(hx + 1, hy, SSD1306_WHITE);
      display.drawPixel(hx + 3, hy, SSD1306_WHITE);
      display.drawPixel(hx + 1, hy - 1, SSD1306_WHITE);
    }
  }

  // --- Blink animation (every ~4 seconds) ---
  if (tgAction == 0 && (t % 4000) < 120) {
    display.fillRect(bobX + 4, bobY + 8, 6, 4, SSD1306_BLACK);
    display.drawFastHLine(bobX + 4, bobY + 10, 6, SSD1306_WHITE);
    display.fillRect(bobX + 14, bobY + 8, 6, 4, SSD1306_BLACK);
    display.drawFastHLine(bobX + 14, bobY + 10, 6, SSD1306_WHITE);
  }

  // ====== RIGHT SIDE: Info Panel ======
  int px = 34;  // panel X start

  // Mood text
  display.setCursor(px, 1);
  display.print("Ghost: ");
  display.print(moodText);

  // Separator
  display.drawFastHLine(px, 10, 94, SSD1306_WHITE);

  // Stat bars (compact)
  // Hunger
  display.setCursor(px, 13);
  display.print("Food");
  int hBarW = map(constrain(tgHunger, 0, 100), 0, 100, 0, 40);
  display.drawRect(px + 30, 13, 42, 7, SSD1306_WHITE);
  if (hBarW > 0) display.fillRect(px + 31, 14, hBarW, 5, SSD1306_WHITE);

  // Happiness
  display.setCursor(px, 22);
  display.print("Joy");
  int jBarW = map(constrain(tgHappy, 0, 100), 0, 100, 0, 40);
  display.drawRect(px + 30, 22, 42, 7, SSD1306_WHITE);
  if (jBarW > 0) display.fillRect(px + 31, 23, jBarW, 5, SSD1306_WHITE);

  // Energy
  display.setCursor(px, 31);
  display.print("Zzz");
  int eBarW = map(constrain(tgEnergy, 0, 100), 0, 100, 0, 40);
  display.drawRect(px + 30, 31, 42, 7, SSD1306_WHITE);
  if (eBarW > 0) display.fillRect(px + 31, 32, eBarW, 5, SSD1306_WHITE);

  // Age + stats row
  display.setCursor(px, 41);
  display.print("Age:");
  display.print(tgAge);
  display.print("m ");
  display.print("F:");
  display.print(tgFeedCount);
  display.print(" P:");
  display.print(tgPlayCount);

  // ====== BOTTOM: Controls hint ======
  display.drawFastHLine(0, 52, 128, SSD1306_WHITE);
  display.setCursor(1, 55);

  if (tgAction == 0) {
    // Show controls
    display.print("UP");
    display.drawRect(0, 54, 14, 9, SSD1306_WHITE);
    display.setCursor(16, 55);
    display.print("Feed ");

    display.setCursor(50, 55);
    display.print("DN");
    display.drawRect(49, 54, 14, 9, SSD1306_WHITE);
    display.setCursor(65, 55);
    display.print("Play ");

    display.setCursor(100, 55);
    display.print("OK");
    display.drawRect(99, 54, 14, 9, SSD1306_WHITE);
    display.setCursor(115, 55);
    display.print("Slp");
  } else {
    // Show action in progress
    const char* actionNames[] = {"", "Feeding...", "Playing...", "Sleeping..."};
    int nameLen = strlen(actionNames[tgAction]);
    display.setCursor((128 - nameLen * 6) / 2, 55);
    display.print(actionNames[tgAction]);
  }

  display.display();
}

// ============================================================
// Deauth Monitor Screen — live graph with stats
// ============================================================
void drawDeauthMonitorScreen() {
  display.clearDisplay();

  drawHeader("Deauth Monitor");
  display.setTextColor(SSD1306_WHITE);

  // Stats row
  display.setCursor(2, 13);
  display.print("Tot:");
  display.print(deauthMonitorCount);

  display.setCursor(70, 13);
  display.print("Pk:");
  display.print(deauthGraphMax);

  // Graph area
  int graphX = 2;
  int graphY = 23;
  int graphW = 124;
  int graphH = 28;

  drawRoundRect(graphX - 1, graphY - 1, graphW + 2, graphH + 2, false);

  // Dotted grid
  for (int gy = graphY + 7; gy < graphY + graphH; gy += 7) {
    for (int gx = graphX; gx < graphX + graphW; gx += 3) {
      display.drawPixel(gx, gy, SSD1306_WHITE);
    }
  }

  // Graph bars
  int maxVal = max(deauthGraphMax, 1);
  for (int i = 0; i < graphW && i < DEAUTH_GRAPH_WIDTH; i++) {
    int dataIdx = (deauthGraphIndex + i) % DEAUTH_GRAPH_WIDTH;
    int val = deauthGraphData[dataIdx];
    int barH = map(constrain(val, 0, maxVal), 0, maxVal, 0, graphH - 2);
    if (barH > 0) {
      int barX = graphX + (i * graphW / DEAUTH_GRAPH_WIDTH);
      display.drawFastVLine(barX, graphY + graphH - 1 - barH, barH, SSD1306_WHITE);
    }
  }

  // Scanning sweep line
  int scanLineX = graphX + ((millis() / 50) % graphW);
  display.drawFastVLine(scanLineX, graphY, graphH, SSD1306_WHITE);

  drawFooter("BACK=Stop  Live");
  drawActiveIndicator();

  display.display();
}
